"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["99860"],{47687(t){t.exports=JSON.parse('{"tag":{"label":"govtech","permalink":"/sysanalyst-kb.github.io/tech/tags/govtech","allTagsPath":"/sysanalyst-kb.github.io/tech/tags","count":3,"items":[{"id":"astra-linux","title":"Astra Linux \u2014 \u041E\u0421 \u0434\u043B\u044F \u0438\u043C\u043F\u043E\u0440\u0442\u043E\u0437\u0430\u043C\u0435\u0449\u0435\u043D\u0438\u044F","description":"Astra Linux \u2014 \u043E\u0442\u0435\u0447\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u041E\u0421 \u043D\u0430 \u0431\u0430\u0437\u0435 Debian, \u043E\u0441\u043D\u043E\u0432\u043D\u0430\u044F \u0434\u043B\u044F \u0413\u0418\u0421 \u0432 \u0440\u0430\u043C\u043A\u0430\u0445 \u0438\u043C\u043F\u043E\u0440\u0442\u043E\u0437\u0430\u043C\u0435\u0449\u0435\u043D\u0438\u044F (80%+ \u0433\u043E\u0441\u043E\u0440\u0433\u0430\u043D\u043E\u0432 \u0420\u0424). \u0420\u0435\u0434\u0430\u043A\u0446\u0438\u0438 \u0437\u0430\u0449\u0438\u0449\u0451\u043D\u043D\u0430\u044F \u0441\u0440\u0435\u0434\u0430 (\u043F\u0430\u043A\u0435\u0442\u044B Parsec), \u043C\u0430\u043D\u0434\u0430\u0442\u043D\u044B\u0439 \u0434\u043E\u0441\u0442\u0443\u043F, \u0441\u043E\u0432\u043C\u0435\u0441\u0442\u0438\u043C\u043E\u0441\u0442\u044C \u0441 Postgres Pro, 1\u0421 \u0438 \u041A\u0440\u0438\u043F\u0442\u043E\u041F\u0440\u043E. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0432 \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u0438 \u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442: Astra Linux Special Edition (\u0432\u0435\u0440\u0441\u0438\u044F 1.7+), \u0440\u0435\u0436\u0438\u043C \xab\u041E\u0440\u0451\u043B\xbb \u0438\u043B\u0438 \xab\u0421\u043C\u043E\u043B\u0435\u043D\u0441\u043A\xbb \u0432 \u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u0438 \u043E\u0442 \u0443\u0440\u043E\u0432\u043D\u044F \u0437\u0430\u0449\u0438\u0449\u0451\u043D\u043D\u043E\u0441\u0442\u0438.","permalink":"/sysanalyst-kb.github.io/tech/astra-linux"},{"id":"crypto","title":"\u041A\u0440\u0438\u043F\u0442\u043E\u0433\u0440\u0430\u0444\u0438\u044F \u0432 \u0433\u043E\u0441\u0441\u0435\u043A\u0442\u043E\u0440\u0435 (\u0423\u041A\u042D\u041F, PKI, \u0413\u041E\u0421\u0422)","description":"\u041A\u0440\u0438\u043F\u0442\u043E\u0433\u0440\u0430\u0444\u0438\u044F \u0432 \u0413\u0418\u0421 \u043E\u0431\u044F\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u0430 \u0423\u041A\u042D\u041F \u2014 \u0443\u0441\u0438\u043B\u0435\u043D\u043D\u0430\u044F \u043A\u0432\u0430\u043B\u0438\u0444\u0438\u0446\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u0430\u044F \u043F\u043E\u0434\u043F\u0438\u0441\u044C (\u044E\u0440\u0438\u0434\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0441\u0438\u043B\u0430, \u0430\u043D\u0430\u043B\u043E\u0433 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0440\u0443\u0447\u043D\u043E\u0439), PKI \u2014 \u0438\u043D\u0444\u0440\u0430\u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u0430 \u043E\u0442\u043A\u0440\u044B\u0442\u044B\u0445 \u043A\u043B\u044E\u0447\u0435\u0439 + \u0423\u0434\u043E\u0441\u0442\u043E\u0432\u0435\u0440\u044F\u044E\u0449\u0438\u0439 \u0446\u0435\u043D\u0442\u0440, \u041A\u0440\u0438\u043F\u0442\u043E\u041F\u0440\u043E CSP \u2014 \u0431\u0438\u0431\u043B\u0438\u043E\u0442\u0435\u043A\u0430 \u043A\u0440\u0438\u043F\u0442\u043E\u043E\u043F\u0435\u0440\u0430\u0446\u0438\u0439 (95%+ \u0433\u043E\u0441\u043E\u0440\u0433\u0430\u043D\u043E\u0432 \u0420\u0424). \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u0446\u0438\u0440\u0443\u0435\u0442: \u0433\u0434\u0435 \u043D\u0443\u0436\u043D\u0430 \u0423\u041A\u042D\u041F (\u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u044B, \u0421\u041C\u042D\u0412-\u0437\u0430\u043F\u0440\u043E\u0441\u044B), \u043A\u0430\u043A\u043E\u0439 \u0423\u0426 (\u041C\u0438\u043D\u0446\u0438\u0444\u0440\u044B, \u0424\u041D\u0421), \u0444\u043E\u0440\u043C\u0430\u0442 \u043F\u043E\u0434\u043F\u0438\u0441\u0438 (\u043E\u0442\u043A\u0440\u0435\u043F\u043B\u0451\u043D\u043D\u0430\u044F .sig), \u0443\u0440\u043E\u0432\u0435\u043D\u044C \u0421\u041A\u0417\u0418 (\u041A\u04211/\u041A\u04212/\u041A\u04213).","permalink":"/sysanalyst-kb.github.io/tech/crypto"},{"id":"smev","title":"\u0421\u041C\u042D\u0412 \u2014 \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u043C\u0435\u0436\u0432\u0435\u0434\u043E\u043C\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u043E\u0433\u043E \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F","description":"\u0421\u041C\u042D\u0412 \u2014 \u0433\u043E\u0441\u0443\u0434\u0430\u0440\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \xab\u0448\u0438\u043D\u0430\xbb \u0434\u043B\u044F \u043E\u0431\u043C\u0435\u043D\u0430 \u0434\u0430\u043D\u043D\u044B\u043C\u0438 \u043C\u0435\u0436\u0434\u0443 \u0413\u0418\u0421 (25 000+ \u043F\u043E\u0434\u043A\u043B\u044E\u0447\u0451\u043D\u043D\u044B\u0445 \u0441\u0438\u0441\u0442\u0435\u043C, 1B+ \u0437\u0430\u043F\u0440\u043E\u0441\u043E\u0432/\u0433\u043E\u0434). \u0412\u0435\u0440\u0441\u0438\u044F 3 (\u0442\u0435\u043A\u0443\u0449\u0430\u044F) \u2014 REST/JSON, OAuth 2.0 + \u0423\u041A\u042D\u041F, \u0430\u0441\u0438\u043D\u0445\u0440\u043E\u043D\u043D\u044B\u0435 callback. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u0446\u0438\u0440\u0443\u0435\u0442: \u0432\u0438\u0434 \u0441\u0432\u0435\u0434\u0435\u043D\u0438\u044F (\u0447\u0442\u043E \u0437\u0430\u043F\u0440\u0430\u0448\u0438\u0432\u0430\u0435\u043C), \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u044B\u0439 \u0441\u0435\u0440\u0432\u0438\u0441 (\u043A\u0430\u043A), \u043C\u0435\u0442\u0430\u0434\u0430\u043D\u043D\u044B\u0435 (\u0444\u043E\u0440\u043C\u0430\u0442 \u0434\u0430\u043D\u043D\u044B\u0445), SLA (5-30 \u0441\u0435\u043A), \u0442\u0440\u0430\u043D\u0441\u043F\u043E\u0440\u0442 (REST/SOAP). \u0428\u043B\u044E\u0437 \u0421\u041C\u042D\u0412 \u2014 \u0441\u0435\u0440\u0442\u0438\u0444\u0438\u0446\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u0439 \u043A\u043E\u043C\u043F\u043E\u043D\u0435\u043D\u0442 (ViPNet \u0438\u043B\u0438 \u0430\u043B\u044C\u0442\u0435\u0440\u043D\u0430\u0442\u0438\u0432\u0430).","permalink":"/sysanalyst-kb.github.io/tech/smev"}],"unlisted":false}}')}}]);